function substituteSCPI(cmd, params, values) {
  let result = cmd;
  params.forEach(param => {
    const value = values[param.name] ?? param.default;
    result = result.replace(new RegExp(`\\$\\{${param.name}\\}`, 'g'), String(value));
  });
  return result;
}
