def read_timeout_based(sock, timeout=5):
    sock.settimeout(timeout)
    data = bytearray()
    while True:
        try:
            chunk = sock.recv(65536)
            if chunk:
                data.extend(chunk)
            else:
                break
        except socket.timeout:
            if len(data) > 0:
                break  # Timeout = EOF
    return bytes(data)
